#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int gcd(int a, int b) {
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

int main() {
    int n;
    scanf("%d", &n);

    int l;
    if (n % 2 == 0) {
        l = n / 2;
    } else {
        l = (n + 1) / 2;
    }

    double max_value = 0;
    int a1 = 0;
    int b1 = 0;

    for (int i = 0; i < l; i++) {
        int a = i;
        int b = n - i;

        if (gcd(a, b) != 1) {
            continue;
        }

        double ratio = (double)a / b;
        if (ratio > max_value) {
            max_value = ratio;
            a1 = a;
            b1 = b;
        }
    }

    printf("%d %d", a1, b1);
    return 0;
}
